// --- 脚本配置说明 ---
// SWIPE_PREFIX_RULES 定义了每个swipe切换时需要设置的世界书条目状态（基于前缀）。
// 键是swipe的索引（从0开始），值是一个对象，键为"前缀"，值为true(开启)或false(关闭)。
// 脚本会自动扫描所有包含指定前缀的条目并应用状态。

// --- 脚本配置开始 ---
const SWIPE_PREFIX_RULES = {
  // 当切换到第1条Swipe（索引0）时
  0: {
    1: true, // 开启所有以 "1" 开头的条目
    2: false, // 关闭所有以 "2" 开头的条目
    3: false, // 关闭所有以 "3" 开头的条目
    4: false, // 关闭所有以 "4" 开头的条目
    5: false, // 关闭所有以 "5" 开头的条目
  },
  // 当切换到第2条Swipe（索引1）时
  1: {
    1: false,
    2: true,
    3: false,
    4: false,
    5: false,
  },
  // 示例：可以添加更多Swipe索引...
};
// --- 脚本配置结束 ---

// 提取前缀列表 (基于第1条Swipe的配置)
// 按长度降序排序，防止短前缀误匹配长前缀 (如 "1" 匹配 "10")
const PREFIXES = Object.keys(SWIPE_PREFIX_RULES[0] || {}).sort((a, b) => b.length - a.length);

// 全局变量
let currentSwipeIndex = -1;
let isInitialized = false;
let swipeMonitorInterval = null;

// --- 按钮逻辑 ---

/**
 * 手动应用前缀状态
 * @param {string} activePrefix 被激活的前缀
 */
async function applyPrefixState(activePrefix) {
  console.log(`手动切换前缀状态: ${activePrefix}`);

  const lorebookName = TavernHelper.getCurrentCharPrimaryLorebook();
  if (!lorebookName) {
    toastr.warning('当前角色卡没有绑定主要世界书。');
    return;
  }

  try {
    const currentEntries = await TavernHelper.getLorebookEntries(lorebookName);
    if (!currentEntries) {
      console.error(`获取世界书 "${lorebookName}" 条目失败。`);
      return;
    }

    const entriesToModify = [];

    // 遍历所有条目
    for (const entry of currentEntries) {
      const comment = entry.comment || entry.name || '';

      // 检查该条目是否匹配任意已知前缀
      for (const prefix of PREFIXES) {
        if (comment.startsWith(prefix)) {
          // 如果匹配当前激活的前缀 -> 开启
          // 如果匹配其他已知前缀 -> 关闭
          const shouldEnable = (prefix === activePrefix);

          if (entry.enabled !== shouldEnable) {
            entriesToModify.push({
              uid: Number(entry.uid),
              enabled: shouldEnable
            });
          }
          break; // 匹配到一个前缀后就处理下一个条目
        }
      }
    }

    if (entriesToModify.length > 0) {
      await TavernHelper.setLorebookEntries(lorebookName, entriesToModify);
      toastr.success(`已切换至前缀 "${activePrefix}"，更新了 ${entriesToModify.length} 个条目。`, '世界书切换');
    } else {
      toastr.info(`当前已经是 "${activePrefix}" 状态，无需更新。`);
    }

  } catch (error) {
    console.error('切换世界书前缀时发生错误:', error);
    toastr.error('切换失败，详情请看控制台。');
  }
}

function registerPrefixButtons() {
  const buttons = PREFIXES.map(prefix => ({
    name: prefix,
    function: () => applyPrefixState(prefix)
  }));

  // 注册事件
  buttons.forEach(btn => {
    // 先清理旧事件防止重复
    try { eventClearEvent(getButtonEvent(btn.name)); } catch (e) {}
    eventOn(getButtonEvent(btn.name), btn.function);
  });

  // 显示按钮
  replaceScriptButtons(buttons.map(b => ({ name: b.name, visible: true })));
  console.log('前缀切换按钮已注册:', PREFIXES);
}

/**
 * 根据当前swipe索引更新世界书条目状态（基于前缀）。
 * @param {number} swipeIndex 当前swipe的索引。
 */
async function updateWorldBookEntries(swipeIndex) {
  console.log(`准备更新世界书条目（前缀模式），swipe索引: ${swipeIndex}`);

  const lorebookName = TavernHelper.getCurrentCharPrimaryLorebook();
  if (!lorebookName) {
    // 仅在首次初始化时提示，避免频繁打扰
    if (!isInitialized) toastr.info('当前角色卡没有绑定主要世界书，更新未执行。');
    return;
  }

  // 检查配置
  const swipeKey = swipeIndex.toString();
  if (!(swipeKey in SWIPE_PREFIX_RULES)) {
    console.log(`脚本提示：swipe索引 ${swipeIndex} 没有配置前缀规则，忽略。`);
    return;
  }

  const rules = SWIPE_PREFIX_RULES[swipeKey];

  try {
    const currentEntries = await TavernHelper.getLorebookEntries(lorebookName);
    if (!currentEntries) {
      console.error(`获取世界书 "${lorebookName}" 条目失败。`);
      return;
    }

    const entriesToModify = [];
    const prefixes = Object.keys(rules);

    // 遍历所有条目，检查是否匹配任意规则
    for (const entry of currentEntries) {
      const comment = entry.comment || entry.name || '';

      // 找到第一个匹配的前缀
      // 注意：如果有重叠前缀（如 A_ 和 A_B_），这里会匹配到其中一个。
      // 为简单起见，这里假设前缀互不冲突，或者按遍历顺序。
      for (const prefix of prefixes) {
        if (comment.startsWith(prefix)) {
          const targetState = rules[prefix];

          if (entry.enabled !== targetState) {
            entriesToModify.push({
              uid: Number(entry.uid),
              enabled: targetState,
            });
            console.log(`匹配前缀 "${prefix}": 条目 "${comment}" (UID: ${entry.uid}) 状态将变为 ${targetState}`);
          }
          break; // 匹配到一个前缀后就跳出前缀循环
        }
      }
    }

    if (entriesToModify.length > 0) {
      await TavernHelper.setLorebookEntries(lorebookName, entriesToModify);
      toastr.success(`基于前缀规则，已更新 ${entriesToModify.length} 个世界书条目。`, '世界书更新');
    } else {
      console.log('所有匹配前缀的条目状态已正确，无需更新。');
    }

    // 显示当前生效的前缀状态
    const enabledPrefixes = Object.entries(rules)
      .filter(([_, state]) => state)
      .map(([prefix]) => prefix)
      .join(', ');
    const disabledPrefixes = Object.entries(rules)
      .filter(([_, state]) => !state)
      .map(([prefix]) => prefix)
      .join(', ');

    toastr.success(
      `✅ 开启: ${enabledPrefixes || '无'}❌ 关闭: ${disabledPrefixes || '无'}`,
      `世界书前缀状态 (Swipe #${swipeIndex})`,
    );
  } catch (error) {
    console.error('处理世界书条目时发生错误:', error);
  }
}

// --- 监控逻辑 ---

async function getCurrentSwipeIndex() {
  try {
    const messages = await TavernHelper.getChatMessages(0, { include_swipe: true });
    if (!messages || !messages[0]) return -1;
    return messages[0].swipe_id || 0;
  } catch (error) {
    console.error('获取swipe索引出错:', error);
    return -1;
  }
}

async function monitorSwipeChanges() {
  try {
    const newSwipeIndex = await getCurrentSwipeIndex();
    if (currentSwipeIndex !== newSwipeIndex && newSwipeIndex >= 0) {
      const oldIndex = currentSwipeIndex;
      currentSwipeIndex = newSwipeIndex;
      console.log(`检测到swipe变化: ${oldIndex} → ${newSwipeIndex}`);

      if (isInitialized && oldIndex >= 0) {
        toastr.info(`开场白索引变更为 ${newSwipeIndex}`, '自动检测');
      }
      await updateWorldBookEntries(newSwipeIndex);
    }
  } catch (error) {
    console.error(error);
  }
}

function startSwipeMonitor() {
  if (swipeMonitorInterval) clearInterval(swipeMonitorInterval);
  swipeMonitorInterval = setInterval(monitorSwipeChanges, 1000); // 1秒检查一次
  console.log('Swipe前缀监控器已启动');
}

function stopSwipeMonitor() {
  if (swipeMonitorInterval) {
    clearInterval(swipeMonitorInterval);
    swipeMonitorInterval = null;
  }
}

function onScriptLoad() {
  console.log('前缀版Swipe脚本已加载');
  toastr.success('前缀版世界书控制脚本已激活');

  // 注册按钮
  registerPrefixButtons();

  startSwipeMonitor();
  setTimeout(() => {
    isInitialized = true;
    monitorSwipeChanges();
  }, 1000);
}

function onScriptUnload() {
  stopSwipeMonitor();
  replaceScriptButtons([]); // 清理按钮
  console.log('前缀版Swipe脚本已卸载');
}

// 初始化
$(() => onScriptLoad());
$(window).on('pagehide', () => onScriptUnload());
